patch:
--- a/arithmetic_unit.v
+++ b/arithmetic_unit.v
@@ -9,7 +9,7 @@
   output [31:0] result
 );

-  always @(operand_x or operand_y) begin
+  always @(*) begin
     case (operation)
       3'b000: result = operand_x + operand_y;
       3'b001: result = operand_x - operand_y;

before_code:
module arithmetic_unit (
  input [31:0] operand_x,
  input [31:0] operand_y,
  input [2:0] operation,
  output [31:0] result
);

  always @(operand_x or operand_y) begin
    case (operation)
      3'b000: result = operand_x + operand_y;
      3'b001: result = operand_x - operand_y;
      3'b010: result = operand_x & operand_y;
      3'b011: result = operand_x | operand_y;
      default: result = 32'b0;
    endcase
  end
endmodule

after_code:
module arithmetic_unit (
  input [31:0] operand_x,
  input [31:0] operand_y,
  input [2:0] operation,
  output [31:0] result
);

  always @(*) begin
    case (operation)
      3'b000: result = operand_x + operand_y;
      3'b001: result = operand_x - operand_y;
      3'b010: result = operand_x & operand_y;
      3'b011: result = operand_x | operand_y;
      default: result = 32'b0;
    endcase
  end
endmodule
